{
  "title": "कंटेक्स्ट विंडो बेसिक्स",
  "group": "मूल बातें",
  "options": [
    {
      "text": "एक मिनट में अनुरोधों की अधिकतम संख्या"
    },
    {
      "text": "इनपुट और आउटपुट के लिए संयुक्त टोकन सीमा"
    },
    {
      "text": "एक बातचीत में संदेशों की संख्या"
    },
    {
      "text": "सत्रों के बीच उपलब्ध मेमोरी"
    }
  ],
  "questionProse": [
    "एलएलएम में 'कंटेक्स्ट विंडो' किसके लिए उपयोग होता है?"
  ],
  "explanationProse": [
    "कंटेक्स्ट विंडो एकल कॉल में मॉडल द्वारा प्रसंस्कृत टोकन्स की कुल संख्या है — **इनपुट + आउटपुट संयुक्त रूप से**। 128K कंटेक्स्ट विंडो का अर्थ है कि आपका प्रॉम्प्ट + पुनर्प्राप्त दस्तावेज़ + बातचीत का इतिहास + मॉडल का प्रतिक्रिया सभी 128,000 टोकन्स की सीमा में फिट होना चाहिए।\n\nइसका सत्रों, मेमोरी या दर सीमा से कोई लेना-देना नहीं है। जब आप सीमा पर पहुंच जाते हैं, तो मॉडल या तो काट देता है, त्रुटि देता है, या — बदतर — आपके अप्रत्याशित टोकन्स चुपचाप छोड़ देता है।"
  ]
}
